MATCH
  e1:Entity { name: ANY() } -- Core entity node
  e2:Entity {
    name: ANY(),
    ANY([serviceID, jurisdiction, service_type]) WHERE serviceID IS NULL AND jurisdiction IS NULL AND service_type IS NULL
  }
  e3:Other { name: ANY(), type: 'LIMITED LIABILITY COMPANY' }
  -- Intermediary connections
  i1:Intermediary {
    name: ANY(),
    ANY([start_date, end_date, status]) WHERE start_date IS NULL AND end_date IS NULL AND status IS NULL
  }
  -- Address connections
  a1:Address { address: ANY(), countries: ANY() }
  -- Officer connections
  o1:Officer { name: ANY(), ANY([start_date, end_date, status]) WHERE start_date IS NULL AND end_date IS NULL AND status IS NULL }
  -- Relationships forming a 3-node cycle
  e1-[:same_as]->e2,
  e1-[:same_company_as]->e3,
  e2-[:same_name_as]->e3,
  e1-[:connected_to]->a1,
  e2-[:same_as]->i1,
  i1-[:officer_of]->e3,
  o1-[:officer_of]->e3
WHERE
  NOT EXISTS {
    MATCH (e1)-[r]->(e2) WHERE r.type = 'same_as' AND r.link = 'same name and registration date as'
  }
  AND NOT EXISTS {
    MATCH (e1)-[r]->(e3) WHERE r.type = 'same_name_as' AND r.link = 'same name as' AND e3.type = 'LIMITED LIABILITY COMPANY'
  }
LIMIT 100;

